INSERT INTO `t_product` (`shop_id`, `category_id`, `brand_id`, `name`, `subtitle`, `description`, `main_image`, `price`, `original_price`, `stock`, `sales`, `view_count`, `favorite_count`, `review_count`, `avg_review_score`, `is_recommended`, `is_new`, `publish_time`, `status`, `created_by`, `updated_by`) VALUES

-- ====== 数码 ====== (shop_id=1 极客数码旗舰店, category_id=2 手机/电脑/耳机)
(1, 2, 1, 'iPhone 15 Pro', '钛金属设计，A17 Pro芯片，4800万像素主摄', '<p>Apple iPhone 15 Pro 采用钛金属设计，搭载 A17 Pro 芯片，配备 4800 万像素主摄像头。支持 USB-C 接口，动作按钮可自定义功能。</p>', '/images/products/digital_phone.jpg', 7999.00, 8999.00, 50, 120, 3500, 280, 45, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 2, 1, 'MacBook Air M3', '轻薄便携，M3芯片强劲性能，18小时续航', '<p>全新 MacBook Air 搭载 M3 芯片，轻薄设计，支持双屏显示。18小时电池续航，1080p FaceTime 高清摄像头。</p>', '/images/products/digital_laptop.jpg', 8999.00, 9999.00, 30, 80, 2100, 150, 32, 4.9, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 2, 1, 'AirPods Pro 2', '主动降噪，通透模式，空间音频', '<p>AirPods Pro 第二代配备 H2 芯片，主动降噪效果最高提升至 2 倍。支持自适应通透模式，单次充电聆听时间最长可达 6 小时。</p>', '/images/products/digital_earbuds.jpg', 1899.00, 2299.00, 100, 450, 8900, 620, 120, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 2, 2, '华为WATCH GT4', '科学运动减脂，心率监测，14天续航', '<p>华为 WATCH GT 4 支持科学运动减脂功能，配备全新心率监测技术。典型使用场景下续航可达 14 天，支持 100+ 种运动模式。</p>', '/images/products/digital_watch.jpg', 1488.00, 1688.00, 80, 200, 5600, 340, 68, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 美妆 ====== (shop_id=2 美丽佳人, category_id=3 护肤/彩妆/个护)
(2, 3, 3, '雅诗兰黛小棕瓶精华', '第七代特润修护肌活精华露，抗老修护', '<p>雅诗兰黛第七代小棕瓶精华，加速肌因修护，激活细胞新生。早晚使用，肌肤更紧致、更弹润、更透亮。</p>', '/images/products/beauty_serum.jpg', 850.00, 1080.00, 200, 350, 12000, 890, 210, 4.9, 1, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 3, 4, '兰蔻持妆粉底液', '24小时持妆，轻薄透气，遮瑕不假面', '<p>兰蔻持妆轻透粉底液，24小时持久不脱妆。轻薄透气配方，遮瑕不假面，适合各种肤质使用。</p>', '/images/products/beauty_serum.jpg', 420.00, 520.00, 150, 280, 8500, 560, 145, 4.5, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 3, 4, '迪奥烈艳蓝金口红', '999经典正红，丝绒质地，显白不拔干', '<p>迪奥烈艳蓝金唇膏 999，经典正红色号。丝绒质地，显白不拔干，持久显色，一抹尽显高级妆感。</p>', '/images/products/beauty_lipstick.jpg', 380.00, 450.00, 300, 520, 15000, 1200, 380, 4.8, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 3, 6, 'SK-II神仙水', 'PITERA精华，改善肤质，晶莹剔透', '<p>SK-II 护肤精华露（神仙水），蕴含超过 90% PITERA 成分。帮助改善肤质，令肌肤晶莹剔透，焕发自然光彩。</p>', '/images/products/beauty_serum.jpg', 1540.00, 1890.00, 100, 180, 6800, 450, 95, 4.7, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 服装 ====== (shop_id=3 时尚潮流馆, category_id=1 男装/女装/鞋靴)
(3, 1, 7, '优衣库纯棉T恤', '100%新疆长绒棉，柔软亲肤，多色可选', '<p>优衣库经典圆领T恤，采用100%优质新疆长绒棉。触感柔软亲肤，透气吸汗，多色可选，百搭基础款。</p>', '/images/products/clothing_tshirt.jpg', 99.00, 129.00, 500, 1200, 25000, 1800, 420, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 1, 9, 'ZARA碎花连衣裙', '法式浪漫碎花，收腰显瘦，夏日必备', '<p>ZARA 夏季新款碎花连衣裙，法式浪漫设计风格。收腰显瘦剪裁，轻盈透气面料，夏日出游必备单品。</p>', '/images/products/clothing_dress.jpg', 399.00, 499.00, 200, 450, 8900, 670, 180, 4.5, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 1, 8, '耐克Air Max跑鞋', '气垫缓震，透气网面，运动休闲两相宜', '<p>耐克 Air Max 系列跑鞋，经典气垫缓震科技。透气网面设计，轻量舒适，运动休闲两相宜。</p>', '/images/products/sports_shoes.jpg', 899.00, 1099.00, 150, 380, 12000, 890, 220, 4.7, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 1, 14, '阿迪达斯运动T恤', '速干面料，反光细节，夜跑更安全', '<p>阿迪达斯速干运动T恤，采用 CLIMALITE 速干面料。背部透气网眼设计，反光细节保障夜跑安全。</p>', '/images/products/clothing_tshirt.jpg', 299.00, 369.00, 300, 560, 7600, 540, 130, 4.4, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 食品 ====== (shop_id=4 美味食光, category_id=4 零食/饮料/生鲜)
(4, 4, 10, '三只松鼠坚果大礼包', '8种坚果组合，每日一袋，营养均衡', '<p>三只松鼠每日坚果大礼包，精选8种优质坚果与果干。独立小包装，每日一袋，营养均衡，送礼自用两相宜。</p>', '/images/products/food_nuts.jpg', 138.00, 188.00, 1000, 2500, 35000, 2200, 680, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(4, 4, 10, '良品铺子牛肉干', '内蒙古草原牛肉，传统工艺，嚼劲十足', '<p>良品铺子手撕牛肉干，精选内蒙古草原牛肉。传统工艺制作，肉质紧实有嚼劲，越嚼越香。</p>', '/images/products/food_nuts.jpg', 59.00, 79.00, 800, 1800, 18000, 1200, 350, 4.6, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(4, 4, 11, '农夫山泉NFC橙汁', '100%鲜榨，非浓缩还原，维C满满', '<p>农夫山泉 NFC 橙汁，100% 鲜榨非浓缩还原。不加水、不加糖、不加任何添加剂，每一口都是鲜橙原味。</p>', '/images/products/food_fruit.jpg', 68.00, 88.00, 500, 1200, 9500, 680, 190, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(4, 4, 11, '进口新鲜橙子', '南非进口，皮薄多汁，甜度爆表', '<p>南非进口新鲜橙子，阳光充足自然成熟。皮薄易剥，果肉饱满多汁，甜度高达13度以上。</p>', '/images/products/food_fruit.jpg', 39.00, 49.00, 300, 890, 6700, 450, 120, 4.5, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 家居 ====== (shop_id=5 温馨家居, category_id=5 家纺/厨具/收纳)
(5, 5, 12, '无印良品纯棉四件套', '100%有机棉，亲肤透气，简约自然风', '<p>无印良品纯棉四件套，采用100%有机长绒棉。亲肤透气，简约自然设计风格，带来舒适睡眠体验。</p>', '/images/products/home_lamp.jpg', 399.00, 499.00, 100, 280, 7800, 560, 150, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(5, 5, 13, '宜家北欧简约台灯', '实木底座，暖光护眼，卧室床头必备', '<p>宜家北欧风格简约台灯，实木底座稳固耐用。暖光护眼设计，三档亮度可调，卧室床头阅读必备。</p>', '/images/products/home_lamp.jpg', 129.00, 169.00, 200, 560, 12000, 890, 240, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(5, 5, 12, '景德镇陶瓷餐具套装', '手工绘制，釉下彩工艺，安全健康', '<p>景德镇手工陶瓷餐具套装，采用传统釉下彩工艺。高温烧制，安全健康，图案精美，提升用餐仪式感。</p>', '/images/products/home_ceramic.jpg', 259.00, 329.00, 150, 340, 5600, 380, 95, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(5, 5, 13, '宜家多功能收纳盒', '可叠加设计，透明视窗，整理收纳好帮手', '<p>宜家多功能收纳盒，可叠加设计节省空间。透明视窗方便查找，适用于衣柜、书架、厨房等多种场景。</p>', '/images/products/home_ceramic.jpg', 49.00, 69.00, 400, 1200, 18000, 1200, 310, 4.4, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 运动 ====== (shop_id=6 运动世界, category_id=6 运动鞋/运动服/健身器材)
(6, 6, 8, '耐克Zoom Fly跑鞋', '碳纤维板，ZoomX泡棉，马拉松竞速首选', '<p>耐克 Zoom Fly 5 跑鞋，搭载碳纤维板和 ZoomX 泡棉。轻量回弹，助力马拉松训练和比赛，竞速跑者首选。</p>', '/images/products/sports_shoes.jpg', 999.00, 1299.00, 120, 340, 9800, 720, 185, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 6, 14, '阿迪达斯Ultraboost', 'Boost中底，Primeknit鞋面，舒适包裹', '<p>阿迪达斯 Ultraboost 22 跑鞋，全掌 Boost 中底能量回馈。Primeknit 编织鞋面舒适包裹，Continental 马牌橡胶外底。</p>', '/images/products/sports_shoes.jpg', 1099.00, 1399.00, 100, 280, 8500, 610, 160, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 6, 15, '李宁韦德之道篮球鞋', '䨻科技中底，碳板支撑，实战利器', '<p>李宁韦德之道 10 篮球鞋，全掌䨻科技中底提供强劲回弹。碳纤维板加持，实战性能出众，球场焦点。</p>', '/images/products/sports_shoes.jpg', 699.00, 899.00, 80, 220, 6200, 450, 110, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 6, 15, 'TPE防滑瑜伽垫', '环保TPE材质，双面防滑，加厚缓冲', '<p>环保 TPE 材质瑜伽垫，双面防滑纹理设计。6mm 加厚缓冲保护关节，附带背带便于携带，瑜伽健身必备。</p>', '/images/products/sports_yoga.jpg', 89.00, 129.00, 300, 890, 15000, 980, 260, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 图书 ====== (shop_id=7 书香阁, category_id=7 文学/科技/教育)
(7, 7, 16, '《活着》余华', '当代文学经典，人生必读书目，感动千万读者', '<p>余华代表作《活着》，讲述福贵一生的悲欢离合。当代文学经典，入选多个必读书目，感动千万读者。</p>', '/images/products/book_stack.jpg', 35.00, 45.00, 500, 1200, 22000, 1500, 450, 4.9, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 7, 16, '《三体》全集', '刘慈欣科幻巨著，雨果奖获奖作品，中国科幻巅峰', '<p>刘慈欣《三体》三部曲，中国科幻文学巅峰之作。荣获雨果奖等多项国际大奖，探索宇宙文明的宏大叙事。</p>', '/images/products/book_stack.jpg', 98.00, 128.00, 300, 780, 18000, 1200, 380, 4.9, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 7, 16, '《百年孤独》', '马尔克斯魔幻现实主义巨作，诺贝尔文学奖获奖作品', '<p>加西亚·马尔克斯《百年孤独》，魔幻现实主义文学代表作。诺贝尔文学奖获奖作品，布恩迪亚家族七代人的传奇故事。</p>', '/images/products/book_stack.jpg', 55.00, 68.00, 400, 950, 12000, 890, 280, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 7, 17, '《深入理解计算机系统》', 'CSAPP原书第3版，程序员必读经典，深入浅出', '<p>《深入理解计算机系统》原书第3版，Randal E. Bryant 著。程序员必读经典，从程序员视角全面讲解计算机系统。</p>', '/images/products/book_stack.jpg', 139.00, 169.00, 200, 450, 8900, 620, 190, 4.9, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),

-- ====== 母婴 ====== (shop_id=8 宝贝乐园, category_id=8 奶粉/纸尿裤/玩具)
(8, 8, 18, '飞鹤星飞帆3段奶粉', '中国宝宝体质定制，新鲜生牛乳，OPO结构脂', '<p>飞鹤星飞帆 3 段幼儿配方奶粉，专为中国宝宝体质研发。采用新鲜生牛乳，含有 OPO 结构脂，助力宝宝健康成长。</p>', '/images/products/baby_formula.jpg', 268.00, 328.00, 200, 560, 15000, 1100, 320, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(8, 8, 18, '爱他美卓萃2段奶粉', '欧洲进口奶源，益生元组合，接近母乳配方', '<p>爱他美卓萃 2 段较大婴儿配方奶粉，欧洲进口奶源。含有 NuMMOs 益生元组合，配方接近母乳，呵护宝宝肠道健康。</p>', '/images/products/baby_formula.jpg', 298.00, 368.00, 150, 420, 9800, 720, 210, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(8, 8, 18, '花王妙而舒纸尿裤', '日本进口，瞬吸干爽，透气不闷热', '<p>花王妙而舒纸尿裤，日本进口品质。3层瞬吸设计，干爽不反渗，透气腰围不闷热，宝宝舒适妈妈安心。</p>', '/images/products/baby_formula.jpg', 158.00, 198.00, 300, 890, 22000, 1500, 480, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(8, 8, 19, '乐高经典创意积木', '1100+颗粒，无限创意，培养动手能力', '<p>乐高经典创意系列积木套装，含 1100+ 颗粒。色彩丰富形状多样，激发孩子无限创意，培养动手能力和空间想象力。</p>', '/images/products/baby_formula.jpg', 399.00, 499.00, 100, 280, 12000, 890, 240, 4.9, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1);

